import keyword

# ── 1. kwlist basics ──────────────────────────────────────────────────────────
print(isinstance(keyword.kwlist, list))
print(len(keyword.kwlist) == 35)
print(all(isinstance(k, str) for k in keyword.kwlist))

# ── 2. All 35 hard keywords present ───────────────────────────────────────────
print('False' in keyword.kwlist)
print('None' in keyword.kwlist)
print('True' in keyword.kwlist)
print('and' in keyword.kwlist)
print('as' in keyword.kwlist)
print('assert' in keyword.kwlist)
print('async' in keyword.kwlist)
print('await' in keyword.kwlist)
print('break' in keyword.kwlist)
print('class' in keyword.kwlist)
print('continue' in keyword.kwlist)
print('def' in keyword.kwlist)
print('del' in keyword.kwlist)
print('elif' in keyword.kwlist)
print('else' in keyword.kwlist)
print('except' in keyword.kwlist)
print('finally' in keyword.kwlist)
print('for' in keyword.kwlist)
print('from' in keyword.kwlist)
print('global' in keyword.kwlist)
print('if' in keyword.kwlist)
print('import' in keyword.kwlist)
print('in' in keyword.kwlist)
print('is' in keyword.kwlist)
print('lambda' in keyword.kwlist)
print('nonlocal' in keyword.kwlist)
print('not' in keyword.kwlist)
print('or' in keyword.kwlist)
print('pass' in keyword.kwlist)
print('raise' in keyword.kwlist)
print('return' in keyword.kwlist)
print('try' in keyword.kwlist)
print('while' in keyword.kwlist)
print('with' in keyword.kwlist)
print('yield' in keyword.kwlist)

# kwlist is sorted
print(keyword.kwlist == sorted(keyword.kwlist))

# ── 3. softkwlist basics ──────────────────────────────────────────────────────
print(isinstance(keyword.softkwlist, list))
print(len(keyword.softkwlist) == 4)
print(all(isinstance(k, str) for k in keyword.softkwlist))
print('_' in keyword.softkwlist)
print('case' in keyword.softkwlist)
print('match' in keyword.softkwlist)
print('type' in keyword.softkwlist)
print(keyword.softkwlist == sorted(keyword.softkwlist))

# ── 4. iskeyword — True for every hard keyword ────────────────────────────────
print(keyword.iskeyword('False'))
print(keyword.iskeyword('None'))
print(keyword.iskeyword('True'))
print(keyword.iskeyword('and'))
print(keyword.iskeyword('as'))
print(keyword.iskeyword('assert'))
print(keyword.iskeyword('async'))
print(keyword.iskeyword('await'))
print(keyword.iskeyword('break'))
print(keyword.iskeyword('class'))
print(keyword.iskeyword('continue'))
print(keyword.iskeyword('def'))
print(keyword.iskeyword('del'))
print(keyword.iskeyword('elif'))
print(keyword.iskeyword('else'))
print(keyword.iskeyword('except'))
print(keyword.iskeyword('finally'))
print(keyword.iskeyword('for'))
print(keyword.iskeyword('from'))
print(keyword.iskeyword('global'))
print(keyword.iskeyword('if'))
print(keyword.iskeyword('import'))
print(keyword.iskeyword('in'))
print(keyword.iskeyword('is'))
print(keyword.iskeyword('lambda'))
print(keyword.iskeyword('nonlocal'))
print(keyword.iskeyword('not'))
print(keyword.iskeyword('or'))
print(keyword.iskeyword('pass'))
print(keyword.iskeyword('raise'))
print(keyword.iskeyword('return'))
print(keyword.iskeyword('try'))
print(keyword.iskeyword('while'))
print(keyword.iskeyword('with'))
print(keyword.iskeyword('yield'))

# ── 5. iskeyword — False for non-keywords ────────────────────────────────────
print(keyword.iskeyword('foo') == False)
print(keyword.iskeyword('match') == False)
print(keyword.iskeyword('case') == False)
print(keyword.iskeyword('type') == False)
print(keyword.iskeyword('_') == False)
print(keyword.iskeyword('') == False)
print(keyword.iskeyword('IF') == False)
print(keyword.iskeyword('For') == False)

# ── 6. issoftkeyword — True for every soft keyword ───────────────────────────
print(keyword.issoftkeyword('_'))
print(keyword.issoftkeyword('case'))
print(keyword.issoftkeyword('match'))
print(keyword.issoftkeyword('type'))

# ── 7. issoftkeyword — False for hard keywords and non-keywords ──────────────
print(keyword.issoftkeyword('if') == False)
print(keyword.issoftkeyword('for') == False)
print(keyword.issoftkeyword('foo') == False)
print(keyword.issoftkeyword('') == False)
print(keyword.issoftkeyword('Match') == False)

# ── 8. iskeyword agrees with kwlist membership ────────────────────────────────
print(all(keyword.iskeyword(k) for k in keyword.kwlist))
print(not any(keyword.iskeyword(k) for k in keyword.softkwlist))

# ── 9. issoftkeyword agrees with softkwlist membership ───────────────────────
print(all(keyword.issoftkeyword(k) for k in keyword.softkwlist))
print(not any(keyword.issoftkeyword(k) for k in keyword.kwlist))

print('done')
